mapper.select:
SELECT ID, NAME, URL, LOGO, DESCRIPTION, STATUS, IS_VISIBLE, ALLOW_FOLLOW, SORT, CREATE_TIME
FROM friend_link fl



        AND fl.NAME LIKE #{nameBind}



        AND fl.URL LIKE #{urlBind}


        AND fl.STATUS = #{query.status}


        AND fl.IS_VISIBLE = #{query.isVisible}


        AND t.ALLOW_FOLLOW = #{query.allowFollow}


ORDER BY fl.SORT DESC, fl.CREATE_TIME DESC
